(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[4589],{6378:(e,a,s)=>{"use strict";s.r(a),s.d(a,{data:()=>n});const n={key:"v-0b7a73ce",path:"/sql/data/delete/",title:"DELETE FROM",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Delete based on another table",slug:"delete-based-on-another-table",children:[]},{level:2,title:"Delete all rows in table",slug:"delete-all-rows-in-table",children:[]}],filePathRelative:"sql/data/delete/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1289:(e,a,s)=>{"use strict";s.r(a),s.d(a,{default:()=>l});const n=(0,s(6252).uE)('<h1 id="delete-from" tabindex="-1"><a class="header-anchor" href="#delete-from" aria-hidden="true">#</a> DELETE FROM</h1><p>Delete will delete a certain row that met the <code>WHERE</code> condition.</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> table_name\n<span class="token keyword">WHERE</span> condition<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>the rows can be deleted from table when certain condition is met</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> employee\n<span class="token keyword">WHERE</span> first_name <span class="token operator">=</span> <span class="token string">&#39;John&#39;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>and you can use all <code>WHERE</code> clause wheaver you liked to</p><h2 id="delete-based-on-another-table" tabindex="-1"><a class="header-anchor" href="#delete-based-on-another-table" aria-hidden="true">#</a> Delete based on another table</h2><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> sales_reps\n<span class="token keyword">WHERE</span> reps_id <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">SELECT</span> employee_id\n<span class="token keyword">FROM</span> employees\n<span class="token keyword">WHERE</span> last_name <span class="token operator">=</span> <span class="token string">&#39;Banda&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  \n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="delete-all-rows-in-table" tabindex="-1"><a class="header-anchor" href="#delete-all-rows-in-table" aria-hidden="true">#</a> Delete all rows in table</h2><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> sales_reps\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>This will delete data from the table, but the column will remains</p>',11),l={render:function(e,a){return n}}}}]);